const content = FILE_CONTENT;
const lines = content.split('\n');

// Parse the diff to identify key changes
const files = [];
let currentFile = null;
let additions = 0, deletions = 0;

for (const line of lines) {
  if (line.startsWith('diff --git')) {
    if (currentFile) {
      files.push(currentFile);
    }
    const match = line.match(/b\/(.+)$/);
    currentFile = { name: match ? match[1] : 'unknown', adds: 0, dels: 0 };
  } else if (line.startsWith('+++') || line.startsWith('---')) {
    continue;
  } else if (line.startsWith('+') && !line.startsWith('+++')) {
    if (currentFile) currentFile.adds++;
    additions++;
  } else if (line.startsWith('-') && !line.startsWith('---')) {
    if (currentFile) currentFile.dels++;
    deletions++;
  }
}
if (currentFile) files.push(currentFile);

// Identify key changes by file category
const categories = {
  schema: files.filter(f => f.name.includes('schema/')),
  tests: files.filter(f => f.name.includes('tests/')),
  docs: files.filter(f => f.name.includes('docs/')),
  extraction: files.filter(f => f.name.includes('extraction/')),
  iam: files.filter(f => f.name.includes('iam/')),
  workspace: files.filter(f => f.name.includes('workspace/')),
  other: files.filter(f => !f.name.includes('schema/') && !f.name.includes('tests/') && !f.name.includes('docs/') && !f.name.includes('extraction/') && !f.name.includes('iam/') && !f.name.includes('workspace/'))
};

console.log('=== PR Diff Summary ===\n');
console.log(`Total files changed: ${files.length}`);
console.log(`Total additions: ${additions}`);
console.log(`Total deletions: ${deletions}\n`);

console.log('=== Key Areas Changed ===\n');
if (categories.schema.length > 0) {
  console.log(`Schema migrations (${categories.schema.length} files):`);
  categories.schema.forEach(f => console.log(`  - ${f.name}`));
  console.log('');
}
if (categories.docs.length > 0) {
  console.log(`Documentation (${categories.docs.length} files):`);
  categories.docs.slice(0, 5).forEach(f => console.log(`  - ${f.name}`));
  if (categories.docs.length > 5) console.log(`  ... and ${categories.docs.length - 5} more`);
  console.log('');
}
if (categories.tests.length > 0) {
  console.log(`Tests (${categories.tests.length} files):`);
  categories.tests.slice(0, 5).forEach(f => console.log(`  - ${f.name}`));
  if (categories.tests.length > 5) console.log(`  ... and ${categories.tests.length - 5} more`);
  console.log('');
}
if (categories.extraction.length > 0) {
  console.log(`Extraction layer (${categories.extraction.length} files):`);
  categories.extraction.forEach(f => console.log(`  - ${f.name}`));
  console.log('');
}
if (categories.iam.length > 0) {
  console.log(`IAM/Identity (${categories.iam.length} files):`);
  categories.iam.forEach(f => console.log(`  - ${f.name}`));
  console.log('');
}
if (categories.workspace.length > 0) {
  console.log(`Workspace (${categories.workspace.length} files):`);
  categories.workspace.forEach(f => console.log(`  - ${f.name}`));
  console.log('');
}
if (categories.other.length > 0) {
  console.log(`Other (${categories.other.length} files):`);
  categories.other.forEach(f => console.log(`  - ${f.name}`));
}

